115	function Guard({ component: Component, adminOnly = false, ...props }: any) {
116	  const { user, isLoading } = useAuth();
117	  if (isLoading) return (
118	    <div className="flex items-center justify-center min-h-screen bg-[#0a0910]">
119	      <div className="w-6 h-6 rounded-full border-2 animate-spin" style={{ borderColor: "#d4b461", borderTopColor: "transparent" }} />
120	    </div>
121	  );
122	  if (!user) return <Redirect to="/login" />;
123	  if (adminOnly && (user as any).role !== "admin") return <Redirect to="/dashboard" />;
124	  if ((user as any).role !== "admin" && !(user as any).surveyCompleted) return <Redirect to="/onboarding" />;
125	  if ((user as any).role !== "admin" && !user.planConfirmed) return <Redirect to="/select-plan" />;
126	  return <Component {...props} />;
127	}
128	
129	function HomeRedirect() {
130	  const { user, isLoading } = useAuth();
131	  if (isLoading) return (
132	    <div className="flex items-center justify-center min-h-screen bg-[#0a0910]">
133	      <div className="w-6 h-6 rounded-full border-2 animate-spin" style={{ borderColor: "#d4b461", borderTopColor: "transparent" }} />
134	    </div>
135	  );
136	  if (!user) return <OraviniLanding />;
137	  if ((user as any).role === "admin") return <Redirect to="/admin" />;
138	  if (!(user as any).surveyCompleted) return <Redirect to="/onboarding" />;
139	  if (!user.planConfirmed) return <Redirect to="/select-plan" />;
140	  return <Redirect to="/dashboard" />;
141	}
