1756	function genAttendanceTimeline(registrations: number, durationMins: number, seed: number): number[] {
1757	  const intervals = Math.ceil(durationMins / 5);
1758	  const peak = Math.round(registrations * (0.55 + (seed % 4) * 0.05));
1759	  const timeline: number[] = [];
1760	  for (let i = 0; i <= intervals; i++) {
1761	    const pct = i / intervals;
1762	    let val: number;
1763	    if (pct < 0.15) {
1764	      val = Math.round(peak * (pct / 0.15) * (0.7 + (seed % 3) * 0.05));
1765	    } else if (pct < 0.3) {
1766	      val = Math.round(peak * (0.85 + (seed % 4) * 0.02));
1767	    } else {
1768	      const decay = Math.pow(1 - (pct - 0.3) / 0.7, 1.2 + (seed % 3) * 0.1);
1769	      val = Math.round(peak * decay * (0.5 + (seed % 5) * 0.06));
1770	    }
1771	    timeline.push(Math.max(0, val));
1772	  }
1773	  return timeline;
1774	}
1775	
1776	function genJoinLeaveData(registrations: number, seed: number): { joins: number[]; leaves: number[] } {
1777	  const slots = 12;
1778	  const joins: number[] = [];
1779	  const leaves: number[] = [];
1780	  let totalJoined = 0;
1781	  for (let i = 0; i < slots; i++) {
1782	    const joinWeight = i < 3 ? 0.35 - i * 0.08 : i < 6 ? 0.08 : 0.02;
1783	    const j = Math.round(registrations * joinWeight * (0.8 + ((seed + i) % 4) * 0.07));
1784	    joins.push(j);
1785	    totalJoined += j;
1786	  }
1787	  for (let i = 0; i < slots; i++) {
1788	    const leaveWeight = i < 2 ? 0.04 : i < 5 ? 0.07 : i < 9 ? 0.1 : 0.2;
1789	    const l = Math.round(totalJoined * leaveWeight * (0.7 + ((seed + i) % 5) * 0.08));
1790	    leaves.push(l);
1791	  }
1792	  return { joins, leaves };
1793	}
