                                    : "border-zinc-800 hover:border-zinc-600"
                                }`}
                            style={
                                p.highlight
                                    ? {
                                        background:
                                            "linear-gradient(180deg, rgba(212,180,97,0.08), rgba(18,14,30,0.6))",
